from flask import Flask, request, jsonify
from graphene import ObjectType, String, Schema, Field, List, Int
from graphene_sqlalchemy import SQLAlchemyObjectType, SQLAlchemyConnectionField
from flask_graphql import GraphQLView
from sqlalchemy import create_engine, Column, Integer, String as SQLString, ForeignKey
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker, relationship

# SQLAlchemy setup
Base = declarative_base()
engine = create_engine('sqlite:///ecommerce.db')
Session = sessionmaker(bind=engine)
session = Session()

class ProductModel(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(SQLString)
    category_id = Column(Integer, ForeignKey('categories.id'))
    reviews = relationship('ReviewModel', back_populates='product')

class CategoryModel(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(SQLString)
    products = relationship('ProductModel', back_populates='category')

class ReviewModel(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    content = Column(SQLString)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship('ProductModel', back_populates='reviews')

Base.metadata.create_all(engine)

# Graphene setup
class Product(SQLAlchemyObjectType):
    class Meta:
        model = ProductModel

class Category(SQLAlchemyObjectType):
    class Meta:
        model = CategoryModel

class Review(SQLAlchemyObjectType):
    class Meta:
        model = ReviewModel

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)
    reviews = List(Review, product_id=Int())

    def resolve_products(self, info):
        return session.query(ProductModel).all()

    def resolve_categories(self, info):
        return session.query(CategoryModel).all()

    def resolve_reviews(self, info, product_id=None):
        query = session.query(ReviewModel)
        if product_id:
            query = query.filter(ReviewModel.product_id == product_id)
        return query.all()

schema = Schema(query=Query)

# Flask setup
app = Flask(__name__)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True  # Introspection enabled for development
    )
)

@app.route('/')
def index():
    return jsonify({"message": "Welcome to the E-commerce API"})

if __name__ == '__main__':
    app.run(debug=True)